import { useState, useRef, useEffect } from "react";
import { useLang } from "../../context/LangContext";
import "./ClassifyPage.css";

const AI_URL = process.env.REACT_APP_AI_URL;
const STEPS = ["upload", "edit", "loading", "result"];

function useCrop() {
  const [crop, setCrop] = useState(null);
  const [dragging, setDragging] = useState(false);
  const startRef = useRef(null);

  const getPos = (e, el) => {
    const rect = el.getBoundingClientRect();
    const touch = e.touches?.[0] ?? e;
    return {
      x: Math.max(0, Math.min(touch.clientX - rect.left, rect.width)),
      y: Math.max(0, Math.min(touch.clientY - rect.top, rect.height)),
    };
  };

  const onStart = (e, el) => {
    const pos = getPos(e, el);
    startRef.current = pos;
    setCrop({ x: pos.x, y: pos.y, x2: pos.x, y2: pos.y });
    setDragging(true);
  };

  const onMove = (e, el) => {
    if (!dragging || !startRef.current) return;
    const pos = getPos(e, el);
    setCrop({
      x: Math.min(startRef.current.x, pos.x),
      y: Math.min(startRef.current.y, pos.y),
      x2: Math.max(startRef.current.x, pos.x),
      y2: Math.max(startRef.current.y, pos.y),
    });
  };

  const onEnd = () => setDragging(false);
  const reset = () => {
    setCrop(null);
    startRef.current = null;
  };

  return { crop, onStart, onMove, onEnd, reset };
}

export default function ClassifyPage() {
  const { lang } = useLang();

  const [step, setStep] = useState("upload");
  const [file, setFile] = useState(null);
  const [preview, setPreview] = useState(null);
  const [imgObj, setImgObj] = useState(null);
  const [result, setResult] = useState(null);

  const [adj, setAdj] = useState({
    brightness: 1,
    contrast: 1,
    color: 1,
  });

  const canvasRef = useRef(null);
  const cropRef = useRef(null);
  const fileInputRef = useRef(null);

  const { crop, onStart, onMove, onEnd, reset } = useCrop();

  const STEPS_INDEX = STEPS.indexOf(step);

  // ---------------------------
  // load image to canvas
  // ---------------------------
  useEffect(() => {
    if (!preview) return;

    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");

    const img = new Image();
    img.src = preview;

    img.onload = () => {
      canvas.width = img.width;
      canvas.height = img.height;
      ctx.drawImage(img, 0, 0);
      setImgObj(img);
    };
  }, [preview]);

  // ---------------------------
  // apply filters real-time
  // ---------------------------
  useEffect(() => {
    if (!imgObj) return;

    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");

    ctx.clearRect(0, 0, canvas.width, canvas.height);

    ctx.filter = `
      brightness(${adj.brightness})
      contrast(${adj.contrast})
      saturate(${adj.color})
    `;

    ctx.drawImage(imgObj, 0, 0);
  }, [adj, imgObj]);

  // ---------------------------
  // file upload
  // ---------------------------
  const handleFile = (f) => {
    if (!f || !f.type.startsWith("image/")) return;

    setFile(f);
    setPreview(URL.createObjectURL(f));
    setStep("edit");

    setAdj({
      brightness: 1,
      contrast: 1,
      color: 1,
    });

    reset();
  };

  // ---------------------------
  // crop + export image
  // ---------------------------
  const exportImage = () => {
    const canvas = canvasRef.current;

    if (!crop) {
      return canvas.toDataURL("image/jpeg");
    }

    const temp = document.createElement("canvas");
    const tctx = temp.getContext("2d");

    const scaleX = canvas.width / cropRef.current.clientWidth;
    const scaleY = canvas.height / cropRef.current.clientHeight;

    const x = crop.x * scaleX;
    const y = crop.y * scaleY;
    const w = (crop.x2 - crop.x) * scaleX;
    const h = (crop.y2 - crop.y) * scaleY;

    temp.width = w;
    temp.height = h;

    tctx.drawImage(canvas, x, y, w, h, 0, 0, w, h);

    return temp.toDataURL("image/jpeg");
  };

  // ---------------------------
  // send to AI
  // ---------------------------
  const handleAnalyze = async () => {
    setStep("loading");

    const base64 = exportImage().split(",")[1];

    const res = await fetch(`${AI_URL}/predict`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        file: base64,
      }),
    });

    const data = await res.json();

    setResult(data);
    setStep("result");
  };

  // ---------------------------
  // UI
  // ---------------------------
  return (
    <div className="cls-wrapper">

      {/* steps */}
      <div className="cls-steps">
        {["Upload", "Edit", "Result"].map((s, i) => (
          <div key={i} className={`cls-step ${STEPS_INDEX >= i ? "active" : ""}`}>
            {s}
          </div>
        ))}
      </div>

      {/* upload */}
      {step === "upload" && (
        <div
          className="cls-dropzone"
          onClick={() => fileInputRef.current.click()}
        >
          <p>Upload Image</p>

          <input
            ref={fileInputRef}
            type="file"
            hidden
            accept="image/*"
            onChange={(e) => handleFile(e.target.files?.[0])}
          />
        </div>
      )}

      {/* edit */}
      {step === "edit" && (
        <div className="cls-edit-layout">

          {/* canvas */}
          <div
            ref={cropRef}
            onMouseDown={(e) => onStart(e, cropRef.current)}
            onMouseMove={(e) => onMove(e, cropRef.current)}
            onMouseUp={onEnd}
            style={{ position: "relative" }}
          >
            <canvas ref={canvasRef} />
          </div>

          {/* sliders */}
          <div>
            <label>Brightness</label>
            <input
              type="range"
              min="0.5"
              max="2"
              step="0.1"
              value={adj.brightness}
              onChange={(e) =>
                setAdj({ ...adj, brightness: e.target.value })
              }
            />

            <label>Contrast</label>
            <input
              type="range"
              min="0.5"
              max="2"
              step="0.1"
              value={adj.contrast}
              onChange={(e) =>
                setAdj({ ...adj, contrast: e.target.value })
              }
            />

            <label>Saturation</label>
            <input
              type="range"
              min="0"
              max="2"
              step="0.1"
              value={adj.color}
              onChange={(e) =>
                setAdj({ ...adj, color: e.target.value })
              }
            />
          </div>

          <button onClick={handleAnalyze}>
            Analyze
          </button>
        </div>
      )}

      {/* loading */}
      {step === "loading" && <p>Loading...</p>}

      {/* result */}
      {step === "result" && result && (
        <div>
          <h2>{result.top?.label}</h2>

          <button onClick={() => setStep("edit")}>
            Edit again
          </button>

          <button onClick={() => setStep("upload")}>
            New image
          </button>
        </div>
      )}

    </div>
  );
}
